```class Solution {
public:
    bool canMakeSubsequence(string str1, string str2) {
        int m = str1.size(), n = str2.size();
        int j = 0;
        for (int i = 0; i < m; ++i) {
            if (str1[i] == str2[j]) {
                ++j;
                if (j == n) return true;
            }
            if (str1[i] + 1 <= 'z' && str1[i] + 1 == str2[j]) {
                ++j;
                if (j == n) return true;
            }
            if (str1[i] == 'z' && str2[j] == 'a') {
                ++j;
                if (j == n) return true;
            }
        }
        return false;
    }
};
